#nullable enable // autogenerated

using MVZ2.GameContent.Detections;
using MVZ2.GameContent.Effects;
using MVZ2.GameContent.Entities;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Detections;
using MVZ2.Vanilla.Enemies;
using MVZ2.Vanilla.Entities;
using MVZ2Logic.Entities;
using MVZ2.Vanilla.Grids;
using MVZ2Logic.Grids;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Entities;
using PVZEngine;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using Tools;
using UnityEngine;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEnemyNames.hacker)]
    public class Hacker : AIEntityBehaviour
    {
        public Hacker(string nsp, string name) : base(nsp, name)
        {
        }
        protected override void UpdateAI(Entity enemy)
        {
            base.UpdateAI(enemy);
            switch (enemy.State)
            {
                case STATE_HACK:
                    UpdateHack(enemy);
                    break;
                default:
                    UpdateNotHack(enemy);
                    break;
            }
        }
        private void UpdateHack(Entity enemy)
        {
            var timer = GetHackTimer(enemy);
            if (timer == null)
            {
                timer = TimerHelper.NewSecondTimer(HACK_DURATION_SECONDS);
                SetHackTimer(enemy, timer);
            }
            if (timer.RunToExpired(enemy.GetAttackSpeed()))
            {
                FindAndHack(enemy);
                timer.Reset();
            }
        }
        private void UpdateNotHack(Entity enemy)
        {
            var timer = GetHackTimer(enemy);
            if (timer != null)
            {
                timer.Reset();
            }
        }
        public static void FindAndHack(Entity enemy)
        {
            var facingX = enemy.GetFacingX();
            var column = enemy.GetColumn();
            var target = detector.DetectEntityWithTheMost(enemy, t =>
            {
                var value = (t.GetColumn() - column) * facingX * 100;
                var grid = t.GetGrid();
                if (grid != null)
                {
                    if (t.IsTakingGridLayer(grid, VanillaGridLayers.protector))
                        value += 1;
                    else if (t.IsTakingGridLayer(grid, VanillaGridLayers.main))
                        value += 0;
                    else if (t.IsTakingGridLayer(grid, VanillaGridLayers.carrier))
                        value += -1;
                }
                return value;
            });
            if (target == null)
                return;
            Hack(enemy, target);
        }
        public static void Hack(Entity enemy, Entity target)
        {
            enemy.PlaySound(VanillaSoundID.dataStream);
            target.PlaySound(VanillaSoundID.powerOff);
            target.ShortCircuit(Ticks.FromSeconds(HACK_EFFECT_DURATION_SECONDS), new EntitySourceReference(enemy));

            var param = target.GetSpawnParams();
            param.SetProperty(EngineEntityProps.TINT, Color.green);
            target.Spawn(VanillaEffectID.binaryParticles, target.GetCenter(), param);
        }
        public static bool CanHack(Entity enemy)
        {
            return enemy.Position.x <= enemy.Level.GetEntityColumnX(enemy.Level.GetMaxColumnCount() - 1) && detector.DetectExists(enemy);
        }
        public static FrameTimer? GetHackTimer(Entity enemy) => enemy.GetBehaviourField<FrameTimer>(PROP_HACK_TIMER);
        public static void SetHackTimer(Entity enemy, FrameTimer? value) => enemy.SetBehaviourField(PROP_HACK_TIMER, value);
        private static Detector detector = new HackerDetector()
        {
            canDetectInvisible = false
        };
        public const float HACK_DURATION_SECONDS = 8f;
        public const float HACK_EFFECT_DURATION_SECONDS = 32f;
        public static readonly VanillaEntityPropertyMeta<FrameTimer> PROP_HACK_TIMER = new VanillaEntityPropertyMeta<FrameTimer>("hack_timer");
        public const int STATE_WALK = LogicEnemyStates.WALK;
        public const int STATE_HACK = VanillaEnemyStates.HACKER_HACK;
    }
}
